// Recupero dell'input unificato della chiamata
const item = $input.first().json;
const owner = item.owner_data || {};
const body = item.body || {};

const COSTO = 20;
const timestamp = new Date().toISOString();

// 1. Identificazione dell'operatore target nell'array (Sara - Indice 1)
const opIndex = parseInt(body.operator_id);
if (isNaN(opIndex) || !owner.operators || !owner.operators[opIndex]) {
    throw new Error("Errore: Operatore non trovato nell'anagrafica aziendale.");
}

const targetOp = owner.operators[opIndex];

// 2. Controllo Antiduplicazione ed evitare doppi addebiti
let inviteLink = "";
const BOT_NAME = "TrinAi_Team_bot";

if (targetOp.status === "PENDING" && targetOp.invitation_code) {
    // Caso Recupero: Invito già esistente, restituiamo il link senza scalare crediti
    inviteLink = `https://t.me/${BOT_NAME}?start=${targetOp.invitation_code}`;

    return [{
        json: {
            success: true,
            action: "retrieve_existing_invite",
            invite_link: inviteLink,
            operator_name: targetOp.OperatorName,
            owner_data: owner // Nessuna modifica al bilancio
        }
    }];
}

if (targetOp.OperatorChatID || targetOp.status === "ACTIVE") {
    throw new Error("Errore: Il collaboratore è già attivo e associato a un ID Telegram.");
}

// 3. Verifica capienza saldo crediti
const previousBalance = owner.credits_balance || 0;
if (previousBalance < COSTO) {
    return [{
        json: {
            success: false,
            error: true,
            code: "INSUFFICIENT_CREDITS",
            message: "Saldo crediti insufficiente per acquistare uno slot operatore."
        }
    }];
}

// 4. Esecuzione Transazione (Addebito 20 Crediti)
const finalBalance = previousBalance - COSTO;
owner.credits_balance = finalBalance;
owner.last_update = timestamp;

// 5. Generazione Codice d'Invito e Stato
const randomPart = Math.random().toString(36).substring(2, 7).toUpperCase();
const invCode = `INV-${owner.vat_number}-${randomPart}`;
inviteLink = `https://t.me/${BOT_NAME}?start=${invCode}`;

// Aggiornamento anagrafica collaboratore specifico
targetOp.invitation_code = invCode;
targetOp.status = "PENDING";

// 6. Generazione Tracciato di Audit (billing_source strutturato come da immagine)
const transaction_summary = {
    model: "operator_invite_logic_v1",
    is_long_context: false,
    usage: { in: 0, out: 0 },
    usd_cost: 0,
    credits_deducted: COSTO,
    previous_balance: previousBalance,
    final_balance: finalBalance,
    timestamp: timestamp,
    billing_source: {
        use: "operator_invitation",
        wh: "https://prod.workflow.trinai.it/webhook/5a58b38d-dfe5-44c2-9d58-34309585c057"
    }
};

// 7. Output strutturato per i nodi di salvataggio MongoDB e risposta WebApp
return [{
    json: {
        success: true,
        action: "generate_new_invite",
        invite_link: inviteLink,
        operator_name: targetOp.OperatorName,
        owner_data: owner,
        transaction_summary: transaction_summary
    }
}];
